template_code:
Type Element = Enregistrement
Debut
    txt  : Chaine;
    suiv : ^Element;
Fin;

Type File = Enregistrement
Debut
    tete  : ^Element;
    queue : ^Element;
Fin;

Procedure Init(Var F : File)
Debut
    F.tete := NIL;
    F.queue := NIL;
Fin;

Procedure Enfiler(Var F : File, s : Chaine)
Var n : ^Element;
Debut
    n := allouer(taille(Element));
    n->txt := s;
    n->suiv := NIL;
    Si F.tete = NIL Alors
        F.tete := n;
        F.queue := n;
    Sinon
        F.queue->suiv := n;
        F.queue := n;
    FinSi
Fin;

Procedure Defiler(Var F : File, Var s : Chaine)
Var t : ^Element;
Debut
    t := F.tete;
    s := t->txt;
    F.tete := t->suiv;
    Si F.tete = NIL Alors F.queue := NIL; FinSi
    liberer(t);
Fin;

Algorithme BinairesAvecFile;
Var
    F : File;
    N, i : Entier;
    x : Chaine;
Debut
    Lire(N);
    Init(F);
    Enfiler(F, "1");

    Pour i := 1 a N Faire
        Defiler(F, x);
        Ecrire(x);
        Si i < N Alors Ecrire(" " ); FinSi

        // TODO: Enfiler(F, Concat(x, "0"))
        // TODO: Enfiler(F, Concat(x, "1"))
    FinPour
Fin.
